// Gold-standard reference topics, hand-annotated per article.
//
// Keyed by fixture filename → article URL → expected topics array. The URL
// is the most stable identifier (article IDs are generated by the model and
// can drift between runs / prompts). Sponsor entries are intentionally
// omitted: the prompt is expected to either skip them or tag them
// differently, and we don't want sponsor wording to anchor the eval.
//
// Add new fixtures by appending another top-level key. Topics here are
// lowercase, hyphenated, and reflect what a human reviewer would call out
// after reading the article — not every adjacent concept the model might
// emit.

export type GoldStandard = Record<string, Record<string, string[]>>;

